CREATE VIEW `ads_short_video_user_epis_consume_view` (`dt`, `product_id`, `user_id`, `series_id`, `epis_num`, `is_toufang`, `mt`, `core`, `source`, `epis_coin_consume_amount`, `epis_cert_consume_amount`) AS SELECT `a`.`dt`, `a`.`product_id`, `a`.`user_id`, `a`.`series_id`, `a`.`epis_num`, if(`b`.`user_id` IS NOT NULL, 1, 2) AS `is_toufang`, `a`.`mt`, `a`.`core`, `a`.`source`, `a`.`epis_coin_consume_amount`, `a`.`epis_cert_consume_amount`
FROM (SELECT `dwm`.`dwm_video_short_video_watch_consume_ed`.`dt`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`product_id`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`user_id`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`series_id`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`epis_num`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`source`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`mt`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`core`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`epis_coin_consume_amount`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`epis_cert_consume_amount`
FROM `dwm`.`dwm_video_short_video_watch_consume_ed`
WHERE (coalesce(`dwm`.`dwm_video_short_video_watch_consume_ed`.`epis_coin_consume_amount`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`epis_cert_consume_amount`)) IS NOT NULL) `a` LEFT OUTER JOIN (SELECT DISTINCT `dwd`.`dwd_user_install_info_ed_view`.`User_Id`
FROM `dwd`.`dwd_user_install_info_ed_view`
WHERE (`dwd`.`dwd_user_install_info_ed_view`.`Product_Id` = 6833) AND (`dwd`.`dwd_user_install_info_ed_view`.`IsDelete` != 1)) `b` ON `a`.`user_id` = `b`.`user_id` UNION ALL SELECT `dwm`.`dwm_video_short_video_watch_consume_ed`.`dt`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`product_id`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`user_id`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`series_id`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`epis_num`, 0 AS `is_toufang`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`mt`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`core`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`source`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`epis_coin_consume_amount`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`epis_cert_consume_amount`
FROM `dwm`.`dwm_video_short_video_watch_consume_ed`
WHERE (coalesce(`dwm`.`dwm_video_short_video_watch_consume_ed`.`epis_coin_consume_amount`, `dwm`.`dwm_video_short_video_watch_consume_ed`.`epis_cert_consume_amount`)) IS NOT NULL;